/// Get DNS seeds for the appropriate Dash network.
inline std::vector<c2pool::dns::DnsSeed> dash_dns_seeds(bool testnet)
{
    return testnet ? dash_testnet_dns_seeds() : dash_mainnet_dns_seeds();
}

/// Get fixed fallback seeds for the appropriate Dash network.
inline std::vector<NetService> dash_fixed_seeds(bool testnet)
{
    return testnet ? dash_testnet_fixed_seeds() : dash_mainnet_fixed_seeds();
}

